async fetchWithCoalescing(
  key: string,
  fetcher: () => Promise<Record<string, unknown> | null>,
): Promise<Record<string, unknown> | null> {
  // Check cache first
  const cached = this.get(key);
  if (cached !== undefined && cached !== null) {
    return cached;
  }

  // Track if this was coalesced
  const wasInFlight = isInFlight(key);

  const data = await coalesce(key, fetcher);

  if (wasInFlight) {
    entityCacheMetrics.recordCoalesced();
  }

  // Cache the result if fetched successfully
  if (data) {
    this.set(key, data);
  }

  return data;
}

function handleActivityEvent(event: ActivityEvent): void {
  const { action, entityType, subjectId } = event;

  // Only handle delete for product entities with valid entityType and entityId
  if (action !== 'delete' || !entityType || !subjectId || !isProductEntity(entityType)) {
    return;
  }

  // Skip public entities - they use their own cache (publicEntityCache)
  if (isPublicStreamEntity(entityType)) {
    return;
  }

  const invalidated = entityCache.invalidateByEntity(entityType, subjectId);

  if (invalidated) {
    logEvent(null, 'debug', 'Entity cache invalidated', {
      entityType,
      subjectId,
      action,
    });
  }
}

httpCache = (options: HttpCacheOptions = {}): MiddlewareHandler<Env> => {
  const { scope = 'private', maxAge = 3600, staleWhileRevalidate = 600, immutable = false } = options;

  // Build directive string once at startup
  const directives = [
    scope,
    `max-age=${maxAge}`,
    ...(staleWhileRevalidate > 0 ? [`stale-while-revalidate=${staleWhileRevalidate}`] : []),
    ...(immutable ? ['immutable'] : []),
  ].join(', ');

  const description = `HTTP ${scope} cache: max-age=${maxAge}s`;

  return xMiddleware(
    {
      functionName: 'httpCache',
      type: 'x-cache',
      name: 'http',
      description,
    },
    async (ctx, next) => {
      await next();

      // Only cache successful GET responses
      if (ctx.req.method === 'GET' && ctx.res.status >= 200 && ctx.res.status < 300) {
        ctx.header('Cache-Control', directives);
      }
    },
  );
}

sendLockoutEmail = (rateLimitKey: string, type: 'totp-lockout') => {
  const email = emailFromKey(rateLimitKey);
  if (!email) return;

  const duration = Math.round(defaultOptions.blockDuration / 60);

  db.select({ email: usersTable.email, name: usersTable.name, language: usersTable.language })
    .from(usersTable)
    .where(eq(usersTable.email, email))
    .limit(1)
    .then(([user]) => {
      if (user)
        sendAccountSecurityEmail(null, user, type, {
          attempts: String(defaultOptions.points),
          duration: String(duration),
        });
    })
    .catch(() => {});
}

function tryFastConsume(key: string, cost: number, budget: number): 'allow' | 'check-db' {
  const now = Date.now();
  const entry = cache.get(key);

  if (!entry || now - entry.windowStart >= WINDOW_MS) {
    // New window — start fresh
    cache.set(key, { consumed: cost, windowStart: now });
    return 'allow';
  }

  const projectedTotal = entry.consumed + cost;

  if (projectedTotal < budget * FAST_PATH_THRESHOLD) {
    entry.consumed = projectedTotal;
    cache.set(key, entry);
    return 'allow';
  }

  // Near or over budget — let the DB path handle it for accuracy
  return 'check-db';
}

logError = (ctx: LogContext, msg: string, error: Error | unknown, meta?: object): void => {
  const base = extractBase(ctx);

  // If not an instance of Error, log as unknown
  if (!(error instanceof Error)) {
    if (!isProduction) eventLogger.error(error);
    else eventLogger.error({ ...base, ...(meta ?? {}), msg, error });
    return;
  }

  const errorDetails = {
    errorName: error.name,
    errorMessage: error.message,
    errorStack: error.stack,
  };

  if (!isProduction) eventLogger.error(error);
  else eventLogger.error({ ...base, ...(meta ?? {}), errorDetails, msg });
}

function sanitizeEmailSubject(value: string, max = 150): string {
  if (!value) return '';
  // Normalize unicode and remove CR/LF + control chars
  let s = value
    .normalize('NFC')
    .replace(/[\r\n]+/g, ' ') // no newlines in headers
    // biome-ignore lint/suspicious/noControlCharactersInRegex: explicit control-char strip is the purpose of this sanitizer.
    .replace(/[\u0000-\u001F\u007F]/g, ' ') // strip control chars
    .replace(/\s{2,}/g, ' ') // collapse whitespace
    .trim();

  if (s.length > max) s = `${s.slice(0, max - 1)}…`;
  return s;
}

bearerAuth = (
options: Parameters<typeof bearerAuthMiddleware>[0]
): MiddlewareHandler =>
bearerAuthMiddleware({
  noAuthenticationHeader: {
    wwwAuthenticateHeader: (c) =>
      `Bearer error="Unauthorized", error_description="Unauthorized", resource_metadata="${new URL(c.req.url).origin}/.well-known/oauth-protected-resource"`,
  },
  invalidAuthenticationHeader: {
    wwwAuthenticateHeader: (c) =>
      `Bearer error="Unauthorized", error_description="Unauthorized", resource_metadata="${new URL(c.req.url).origin}/.well-known/oauth-protected-resource"`,
  },
  ...options,
})

async function deleteColumn(id: string) {
  const existing = await db.query.columnTable.findFirst({
    where: eq(columnTable.id, id),
  });

  if (!existing) {
    throw new HTTPException(404, { message: "Column not found" });
  }

  const [taskCount] = await db
    .select({ count: sql<number>`count(*)` })
    .from(taskTable)
    .where(eq(taskTable.columnId, id));

  if (taskCount && taskCount.count > 0) {
    throw new HTTPException(409, {
      message:
        "Cannot delete column that contains tasks. Move or delete tasks first.",
    });
  }

  await db.delete(columnTable).where(eq(columnTable.id, id));

  return existing;
}

async function reorderColumns(
  projectId: string,
  columns: Array<{ id: string; position: number }>,
) {
  for (const col of columns) {
    const [updated] = await db
      .update(columnTable)
      .set({ position: col.position })
      .where(
        and(eq(columnTable.id, col.id), eq(columnTable.projectId, projectId)),
      )
      .returning({ id: columnTable.id });

    if (!updated) {
      throw new HTTPException(400, {
        message: `Column ${col.id} does not belong to this project`,
      });
    }
  }

  const updated = await db.query.columnTable.findMany({
    where: eq(columnTable.projectId, projectId),
    orderBy: (columns, { asc }) => [asc(columns.position)],
  });

  return updated;
}

